def solve(text):
    fields, current, depth = [], [], 0
    for character in text:
        if character == '(': depth += 1
        elif character == ')': depth -= 1
        if character == ',' and depth == 0:
            fields.append(''.join(current)); current = []
        else: current.append(character)
    fields.append(''.join(current))
    return fields

